19	/*
20	 * Description: Example code for running keyword spotting on Cortex-M boards
21	 */
22	
23	#include "kws_ds_cnn.h"
24	#include "wav_data.h"
25	
26	int16_t audio_buffer[16000]=WAVE_DATA;
27	
28	Timer T;
29	Serial pc(USBTX, USBRX);
30	
31	int main()
32	{
33	  char output_class[12][8] = {"Silence", "Unknown","yes","no","up","down","left","right","on","off","stop","go"};
34	  KWS_DS_CNN kws(audio_buffer);
35	
36	  T.start();
37	  int start=T.read_us();
38	  kws.extract_features(); //extract mfcc features
39	  kws.classify();	  //classify using dnn
40	  int end=T.read_us();
41	  T.stop();
42	  int max_ind = kws.get_top_class(kws.output);
43	  pc.printf("Total time : %d us\r\n",end-start);
44	  printf("Detected %s (%d%%)\r\n",output_class[max_ind],((int)kws.output[max_ind]*100/128));
45	
46	  return 0;
47	}
