44	const q7_t DNN::ip2_bias[IP2_OUT_DIM]=IP2_BIAS;
45	const q7_t DNN::ip3_wt[IP3_WT_DIM]=IP3_WT;
46	const q7_t DNN::ip3_bias[IP3_OUT_DIM]=IP3_BIAS;
47	const q7_t DNN::ip4_wt[IP4_WT_DIM]=IP4_WT;
48	const q7_t DNN::ip4_bias[OUT_DIM]=IP4_BIAS;
49	
50	DNN::DNN()
51	{
52	  scratch_pad = new q7_t[SCRATCH_BUFFER_SIZE];
53	  ip1_out = scratch_pad;
54	  ip2_out = ip1_out+IP1_OUT_DIM;
55	  ip3_out = ip1_out;
56	  vec_buffer = (q15_t*)(ip1_out+IP1_OUT_DIM+IP2_OUT_DIM);
57	  frame_len = FRAME_LEN;
58	  frame_shift = FRAME_SHIFT;
59	  num_mfcc_features = NUM_MFCC_COEFFS;
60	  num_frames = NUM_FRAMES;
61	  num_out_classes = OUT_DIM;
62	  in_dec_bits = MFCC_DEC_BITS;
63	}
64	
65	DNN::~DNN()
66	{
67	  delete scratch_pad;
68	}
