70	void DNN::run_nn(q7_t* in_data, q7_t* out_data)
71	{
72		// Run all layers
73		
74		// IP1 
75		arm_fully_connected_q7(in_data, ip1_wt, IN_DIM, IP1_OUT_DIM, 1, 7, ip1_bias, ip1_out, vec_buffer);
76	        // RELU1
77		arm_relu_q7(ip1_out, IP1_OUT_DIM);
78	
79		// IP2 
80		arm_fully_connected_q7(ip1_out, ip2_wt, IP1_OUT_DIM, IP2_OUT_DIM, 2, 8, ip2_bias, ip2_out, vec_buffer);
81	        // RELU2
82		arm_relu_q7(ip2_out, IP2_OUT_DIM);
83	
84		// IP3 
85		arm_fully_connected_q7(ip2_out, ip3_wt, IP2_OUT_DIM, IP3_OUT_DIM, 2, 9, ip3_bias, ip3_out, vec_buffer);
86	        // RELU3
87		arm_relu_q7(ip3_out, IP3_OUT_DIM);
88	
89		// IP4 
90		arm_fully_connected_q7(ip3_out, ip4_wt, IP3_OUT_DIM, OUT_DIM, 0, 6, ip4_bias, out_data, vec_buffer);
91	
92	}
